/**
 * inject-definitions.js
 *
 * nestjs-trpc가 server.ts를 자동 생성할 때 상수 참조만 복사하고
 * 정의는 복사하지 않는 문제를 해결합니다.
 *
 * 빌드 전에 이 스크립트를 실행하여 필요한 import 문을 추가합니다.
 */

const fs = require('fs');
const path = require('path');

const SERVER_TS_PATH = path.join(__dirname, '../src/server.ts');

// 추가할 import 문
const IMPORTS_TO_ADD = `
// ============================================
// AUTO-INJECTED IMPORTS (DO NOT EDIT)
// Generated by scripts/inject-definitions.js
// ============================================
import {
  // types/product.ts
  PRODUCT_TYPE_ENUM_VALUE,
  // types/common.ts
  DATE_FILTER_TYPE_ENUM_VALUE,
  BUSINESS_TYPE_ENUM_VALUE,
  paginationQuerySchema,
  createPaginatedResponseSchema,
  businessInfoSchema,
  bankInfoSchema,
  // types/brand.ts
  socialMediaPlatformEnumSchema,
  // types/campaign.ts
  campaignProductInputSchema,
  campaignInfluencerInputSchema,
} from './types';
import {
  normalizeTime,
  TIME_FORMAT_REGEX,
  TIME_FORMAT_ERROR_MESSAGE_KO,
} from './utils';
// ============================================
`;

const INJECTION_MARKER = '// AUTO-INJECTED IMPORTS';

function injectImports() {
  if (!fs.existsSync(SERVER_TS_PATH)) {
    console.log('server.ts not found, skipping injection');
    return;
  }

  let content = fs.readFileSync(SERVER_TS_PATH, 'utf-8');

  // 이미 주입되어 있으면 스킵
  if (content.includes(INJECTION_MARKER)) {
    console.log('Imports already injected, skipping');
    return;
  }

  // 기존 import 문 다음에 주입
  // zod import 다음에 추가
  const zodImportMatch = content.match(/import \{ z \} from ["']zod["'];?\n/);
  if (!zodImportMatch) {
    console.error('Could not find zod import in server.ts');
    process.exit(1);
  }

  const insertPoint = zodImportMatch.index + zodImportMatch[0].length;
  const before = content.substring(0, insertPoint);
  const after = content.substring(insertPoint);

  const newContent = before + IMPORTS_TO_ADD + after;

  fs.writeFileSync(SERVER_TS_PATH, newContent, 'utf-8');
  console.log('Successfully injected imports into server.ts');
}

injectImports();